query.sparql:
SELECT ?person ?personLabel WHERE {
  wd:Q761383 wdt:P138 ?person.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?character WHERE {
  ?character wdt:P451 wd:Q4205826.
  ?character wdt:P451 wd:Q4463198.
}

SELECT ?founder ?founderLabel WHERE {
  ?company wdt:P31 wd:Q4830453;
           wdt:P10786 ?incorporationDate;
           wdt:P199 ?division.
  ?founder wdt:P102 wd:Q200202;
           wdt:P210 ?partyChief.
  ?founder wdt:P39 wd:Q200202.
  ?founder rdfs:label ?founderLabel.
  FILTER(LANG(?founderLabel) = "en")
}

SELECT ?work WHERE {
  ?author wdt:P50 wd:Q10000.
  ?work wdt:P50 ?author;
        wdt:P1433 wd:Q123456.
  ?work wdt:P9687 ?title.
  FILTER(CONTAINS(?title, "middle school student"))
}

SELECT ?work ?workLabel WHERE {
  ?work wdt:P50 wd:Q29565.
  FILTER NOT EXISTS { ?work wdt:P6333 wd:Q12345678. } # Replace Q12345678 with the actual QID for the Witcher series
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?state WHERE {
  {
    wd:Q10420480 wdt:P276 ?state.
  } UNION {
    wd:Q10420481 wdt:P276 ?state.
  }
}
